SELECT sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption", sum(bs."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" = 'CO'